input.command:
foreach ($u in @('ahazan','ahazan2','Public')) {
  $p = "C:\Users\$u\.claude\projects"
  if (Test-Path $p) {
    $files = Get-ChildItem -Path $p -Recurse -Filter *.jsonl -ErrorAction SilentlyContinue
    Write-Output "=== $p : $($files.Count) transcripts ==="
  } else {
    Write-Output "=== $p : (no .claude/projects) ==="
  }
}

Get-ChildItem -Path C:\ -Directory -Recurse -Filter '.claude' -Force -ErrorAction SilentlyContinue |
  ForEach-Object {
    $proj = Join-Path $_.FullName 'projects'
    $cnt = 0
    if (Test-Path $proj) { $cnt = (Get-ChildItem $proj -Recurse -Filter *.jsonl -ErrorAction SilentlyContinue).Count }
    [PSCustomObject]@{ ClaudeDir=$_.FullName; Transcripts=$cnt }
  } | Format-Table -AutoSize

Get-ChildItem -Path C:\ -Directory -Recurse -Filter '.claude' -Force -ErrorAction SilentlyContinue |
  ForEach-Object {
    $proj = Join-Path $_.FullName 'projects'
    $cnt = 0
