    [PSCustomObject]@{ ClaudeDir=$_.FullName; Transcripts=$cnt }
  } | Format-Table -AutoSize

$env:CLAUDE_CONFIG_DIR
Write-Output "---AppData/config locations---"
foreach ($p in @("$env:APPDATA\claude","$env:LOCALAPPDATA\claude","$env:USERPROFILE\.config\claude")) {
  if (Test-Path $p) { Write-Output "EXISTS: $p" } else { Write-Output "none: $p" }
}

foreach ($p in @("$env:APPDATA\claude","$env:LOCALAPPDATA\claude")) {
  $j = Get-ChildItem $p -Recurse -Filter *.jsonl -ErrorAction SilentlyContinue
  Write-Output "$p -> $($j.Count) jsonl files"
}

