$dirs = Get-ChildItem -Path C:\Users -Directory -Recurse -Filter '.claude' -Force -ErrorAction SilentlyContinue
foreach ($d in $dirs) {
  $proj = Join-Path $d.FullName 'projects'
  $cnt = 0
  if (Test-Path $proj) { $cnt = (Get-ChildItem $proj -Recurse -Filter *.jsonl -ErrorAction SilentlyContinue).Count }
  "{0,-5} {1}" -f $cnt, $d.FullName
}
